def kill_llama_server() -> None:
  _invalidate_loaded_model_cache()
  pid = _read_pid()
  if pid is None:
    return
  try:
    os.kill(pid, signal.SIGTERM)
    for _ in range(40):
      try:
        os.kill(pid, 0)
        time.sleep(0.3)
      except ProcessLookupError:
        break
    else:
      os.kill(pid, signal.SIGKILL)
  except ProcessLookupError:
    pass
  try:
    os.remove(LLAMA_PID_FILE)
  except FileNotFoundError:
    pass

