function buildDependencyMap(tasks: ConversationTaskDTO[]) {
  const map = new Map<string, string[]>();
  for (const t of tasks) {
    if (t.depends_on) {
      const deps = map.get(t.depends_on) ?? [];
      deps.push(t.id);
      map.set(t.depends_on, deps);
    }
  }
  return map;
}

